class ForecastRepository(
    private val dao: ForecastDao,
    private val api: WeatherApi
) {
    fun getForecasts(): Flow<List<ForecastRecord>> = dao.observeAllForecasts()

    suspend fun refresh() {
        val fresh = api.fetchLatestForecasts()   // suspend network call
        dao.insertAll(fresh)                     // writes to Room
        // no direct UI update here — Room's Flow (above) handles that
    }
}

[ ViewModel.init { repository.refresh() } ]
        │
        ▼
[ UI immediately shows cached Room data via the Flow, THEN
  automatically updates again once refresh() finishes writing ]

