class SyncWorker(context: Context, params: WorkerParameters) :
    CoroutineWorker(context, params) {
    override suspend fun doWork(): Result {
        return try {
            api.uploadLogs()
            Result.success()
        } catch (e: IOException) {
            Result.retry()          // temporary/network issue
        } catch (e: IllegalStateException) {
            Result.failure()        // permanent, unrecoverable issue
        }
    }
}

[ Result.retry() ] ──▶ [ WorkManager reschedules with backoff delay ]
[ Result.failure() ] ──▶ [ WorkManager gives up permanently, no more attempts ]

class MainActivity : ComponentActivity() {
    private val receiver = NetworkChangeReceiver()

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        registerReceiver(receiver, IntentFilter(CONNECTIVITY_ACTION))
        // ⚠️ no matching unregisterReceiver() call anywhere in this class
    }
}

[ MainActivity destroyed ] ──▶ [ receiver is STILL registered,
                                  now referencing a destroyed Activity ]
        │
   later: MainActivity created again (e.g., after rotation)
        │
        ▼
[ Attempting to register the SAME receiver again ]
   ⚠️ can throw an exception, or result in duplicate
      registrations silently reacting multiple times
